// src/pages/FarmDetail.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css'; // Sį»­ dį»„ng lįŗ”i CSS cho form
import './Manager.css'; // Sį»­ dį»„ng lįŗ”i CSS cho bįŗ£ng (nįŗæu bįŗ”n cĆ³ cĆ”c style bįŗ£ng riĆŖng cho activities)

function FarmDetail() {
  const { farmId } = useParams(); // Lįŗ„y farmId tį»« URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role'); // Lįŗ„y vai trĆ² ngĘ°į»i dĆ¹ng Äį» kiį»m tra quyį»n

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form nhįŗ­p bįŗ£n ghi theo dĆµi
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '', // TĆŖn loĆ i - Giį» ÄĆ¢y sįŗ½ ÄĘ°į»£c chį»n tį»« dropdown į» Äįŗ§u trang
    date: '',        // NgĆ y ghi nhįŗ­n
    totalIndividuals: 0, // Tį»ng sį» cĆ” thį» - GiĆ” trį» nĆ y sįŗ½ khĆ“ng ÄĘ°į»£c nhįŗ­p qua UI form nį»Æa
    currentStatus: { // currentStatus vįŗ«n ÄĘ°į»£c giį»Æ trong state Äį» gį»­i lĆŖn backend
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    increase: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    decrease: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    reasonForChange: '',
    verifiedBy: '',
  });

  // HĆ m fetch chi tiįŗæt cĘ” sį» gĆ¢y nuĆ“i vĆ  cĆ”c bįŗ£n ghi theo dĆµi
  const fetchFarmDetails = async () => {
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // Lįŗ„y thĆ“ng tin chi tiįŗæt cĘ” sį» nuĆ“i
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarm(resFarm.data);

      // Nįŗæu cĆ³ dį»Æ liį»u loĆ i, Äįŗ·t giĆ” trį» mįŗ·c Äį»nh cho speciesName trong form hoįŗ”t Äį»ng
      if (resFarm.data.species && resFarm.data.species.length > 0) {
        setActivityFormData(prev => ({
          ...prev,
          speciesName: resFarm.data.species[0].name // Äįŗ·t loĆ i Äįŗ§u tiĆŖn lĆ m mįŗ·c Äį»nh
        }));
      }

      // Lįŗ„y cĆ”c bįŗ£n ghi theo dĆµi biįŗæn Äį»ng cho cĘ” sį» nĆ y
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(resActivities.data);

    } catch (err) {
      console.error('Lį»i khi tįŗ£i chi tiįŗæt cĘ” sį» nuĆ“i hoįŗ·c cĆ”c bįŗ£n ghi theo dĆµi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'KhĆ“ng thį» tįŗ£i chi tiįŗæt cĘ” sį» gĆ¢y nuĆ“i hoįŗ·c cĆ”c bįŗ£n ghi theo dĆµi.');
      // Chuyį»n hĘ°į»ng nįŗæu khĆ“ng tĆ¬m thįŗ„y hoįŗ·c khĆ“ng cĆ³ quyį»n
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/farms');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    console.log("FarmDetail.js: useEffect is running!"); // ThĆŖm console log Äį» kiį»m tra
    if (farmId && token) {
      fetchFarmDetails();
    } else if (!farmId) {
      setError('KhĆ“ng cĆ³ ID cĘ” sį» nuĆ“i Äį» xem chi tiįŗæt.');
      setLoading(false);
    } else if (!token) {
      setError('Bįŗ”n cįŗ§n ÄÄng nhįŗ­p Äį» xem chi tiįŗæt cĘ” sį» nuĆ“i.');
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate]); // ThĆŖm navigate vĆ o dependency array

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    // Xį»­ lĆ½ cĆ”c trĘ°į»ng ÄĘ”n giįŗ£n trį»±c tiįŗæp (speciesName, date, reasonForChange, verifiedBy)
    if (['speciesName', 'date', 'reasonForChange', 'verifiedBy'].includes(name)) {
      newFormData = {
        ...newFormData,
        [name]: value,
      };
    }
    // else if (name === 'totalIndividuals') { // Phįŗ§n nĆ y khĆ“ng cĆ²n cįŗ§n thiįŗæt vĆ¬ trĘ°į»ng input ÄĆ£ bį» xĆ³a
    //   newFormData = {
    //     ...newFormData,
    //     [name]: parseInt(value, 10) || 0,
    //   };
    // }
    else {
      // Xį»­ lĆ½ cĆ”c trĘ°į»ng nested (increase, decrease)
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: {
          ...newFormData[mainField],
          [subField]: {
            ...newFormData[mainField][subField],
            [prop]: parseInt(value, 10) || 0,
          },
        },
      };
    }
    setActivityFormData(newFormData);
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // Äįŗ£m bįŗ£o farmId ÄĘ°į»£c gį»­i cĆ¹ng vį»i dį»Æ liį»u form
      const dataToSend = {
        ...activityFormData,
        farm: farmId, // LiĆŖn kįŗæt bįŗ£n ghi theo dĆµi vį»i farmId
      };
      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('ThĆŖm bįŗ£n ghi theo dĆµi thĆ nh cĆ“ng!');
      // Cįŗ­p nhįŗ­t lįŗ”i danh sĆ”ch activities
      setActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form, giį»Æ lįŗ”i speciesName nįŗæu nĆ³ ÄĆ£ ÄĘ°į»£c chį»n į» trĆŖn
      setActivityFormData(prev => ({
        ...prev,
        date: '',
        totalIndividuals: 0, // Reset vį» 0
        currentStatus: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
        verifiedBy: '',
      }));
    } catch (err) {
      console.error('Lį»i khi thĆŖm bįŗ£n ghi theo dĆµi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Lį»i khi thĆŖm bįŗ£n ghi theo dĆµi.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('Bįŗ”n cĆ³ chįŗÆc chįŗÆn muį»n xĆ³a bįŗ£n ghi nĆ y?')) {
      setMessage('');
      setError('');
      try {
        await axios.delete(`http://localhost:10000/api/farm-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('Bįŗ£n ghi ÄĆ£ ÄĘ°į»£c xĆ³a thĆ nh cĆ“ng.');
        // Cįŗ­p nhįŗ­t lįŗ”i danh sĆ”ch activities sau khi xĆ³a
        setActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Lį»i khi xĆ³a bįŗ£n ghi theo dĆµi:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Lį»i khi xĆ³a bįŗ£n ghi theo dĆµi.');
      }
    }
  };


  if (loading) {
    return <div className="form-container"><p>Äang tįŗ£i dį»Æ liį»u...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lį»i: {error}</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lįŗ”i danh sĆ”ch</button>
      </div>
    );
  }

  if (!farm) {
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>KhĆ“ng tĆ¬m thįŗ„y thĆ“ng tin cĘ” sį» gĆ¢y nuĆ“i.</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lįŗ”i danh sĆ”ch</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      <h2>šļø Sį» nuĆ“i: {farm.tenCoSo}</h2>
      
      {/* ÄĆ£ thay Äį»i Äį» TĆŖn cĘ” sį», Äį»a chį» vĆ  TĆŖn loĆ i ngang hĆ ng */}
      <div className="form-grid"> {/* Sį»­ dį»„ng form-grid Äį» tįŗ”o cĆ”c cį»t */}
        <div className="detail-group">
          <strong>TĆŖn cĘ” sį»:</strong> <p>{farm.tenCoSo}</p>
        </div>
        <div className="detail-group">
          <strong>Äį»a chį»:</strong> <p>{farm.diaChi}</p>
        </div>
        <div className="form-group detail-group"> {/* ÄĆ£ di chuyį»n Ć“ chį»n TĆŖn loĆ i lĆŖn ÄĆ¢y */}
          <label>TĆŖn loĆ i:</label>
          <select
            name="speciesName"
            value={activityFormData.speciesName}
            onChange={handleActivityFormChange}
            required
          >
            <option value="">-- Chį»n loĆ i --</option>
            {farm.species && farm.species.map((species, index) => (
              <option key={index} value={species.name}>
                {species.name}
              </option>
            ))}
          </select>
        </div>
      </div>

      <h3>ThĆŖm bįŗ£n ghi theo dĆµi mį»i:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid"> {/* Sį»­ dį»„ng form-grid Äį» sįŗÆp xįŗæp cĆ”c trĘ°į»ng cį»§a form */}
          {/* TrĘ°į»ng TĆŖn loĆ i ÄĆ£ ÄĘ°į»£c di chuyį»n lĆŖn trĆŖn */}
          <div className="form-group">
            <label>NgĆ y ghi nhįŗ­n:</label>
            <input
              type="date"
              name="date"
              value={activityFormData.date}
              onChange={handleActivityFormChange}
              required
            />
          </div>
          {/* ÄĆ£ bį» Ć“ nhįŗ­p Tį»ng sį» cĆ” thį» */}
          {/*
          <div className="form-group">
            <input
              type="number"
              name="totalIndividuals"
              value={activityFormData.totalIndividuals}
              onChange={handleActivityFormChange}
              min="0"
            />
          </div>
          */}
        </div>

        {/* Phįŗ§n "Hiį»n trįŗ”ng nuĆ“i" ÄĆ£ ÄĘ°į»£c bį» khį»i form nhįŗ­p */}
        {/*
        <h4>Hiį»n trįŗ”ng nuĆ“i:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bį» mįŗ¹:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="currentStatus.parents.male" value={activityFormData.currentStatus.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="currentStatus.parents.female" value={activityFormData.currentStatus.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>CĆ” thį» khĆ”c:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="currentStatus.otherIndividuals.male" value={activityFormData.currentStatus.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="currentStatus.otherIndividuals.female" value={activityFormData.currentStatus.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>KhĆ“ng rĆµ:</label>
                <input type="number" name="currentStatus.otherIndividuals.unidentified" value={activityFormData.currentStatus.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>
        */}

        <h4>TÄng ÄĆ n:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bį» mįŗ¹:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="increase.parents.male" value={activityFormData.increase.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="increase.parents.female" value={activityFormData.increase.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>CĆ” thį» khĆ”c:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="increase.otherIndividuals.male" value={activityFormData.increase.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="increase.otherIndividuals.female" value={activityFormData.increase.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>KhĆ“ng rĆµ:</label>
                <input type="number" name="increase.otherIndividuals.unidentified" value={activityFormData.increase.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>

        <h4>Giįŗ£m ÄĆ n:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bį» mįŗ¹:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="decrease.parents.male" value={activityFormData.decrease.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="decrease.parents.female" value={activityFormData.decrease.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>CĆ” thį» khĆ”c:</h5>
            <div className="form-section-row">
              <div className="form-group">
                <label>Äį»±c:</label>
                <input type="number" name="decrease.otherIndividuals.male" value={activityFormData.decrease.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>CĆ”i:</label>
                <input type="number" name="decrease.otherIndividuals.female" value={activityFormData.decrease.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>KhĆ“ng rĆµ:</label>
                <input type="number" name="decrease.otherIndividuals.unidentified" value={activityFormData.decrease.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>

        <div className="form-grid">
          <div className="form-group">
            <label>NguyĆŖn nhĆ¢n biįŗæn Äį»ng:</label>
            <input
              type="text"
              name="reasonForChange"
              value={activityFormData.reasonForChange}
              onChange={handleActivityFormChange}
            />
